<script setup lang="ts">import{computed,reactive}from'vue';import type{CampaignDraft}from'@/types/advanced';import type{Customer}from'@/types/customer';const props=defineProps<{campaigns:CampaignDraft[];customers:Customer[]}>();const emit=defineEmits<{save:[CampaignDraft];send:[CampaignDraft]}>();const form=reactive({subject:'A quick plan for {{companyName}}',body:'Hi {{companyName}},\n\nWe noticed an opportunity to help your team get more value from RetentionX. Could we schedule a short review?',segment:'High risk'});const selected=computed(()=>props.customers.filter(c=>form.segment==='All'||(form.segment==='High risk'?c.riskLevel==='High':c.underUtilized)));const preview=computed(()=>form.body.replaceAll('{{companyName}}',selected.value[0]?.companyName??'Customer').replaceAll('{{plan}}',selected.value[0]?.plan??'Plan'));const previewSubject=computed(()=>form.subject.replaceAll('{{companyName}}',selected.value[0]?.companyName??'Customer'));function draft(status:'Draft'|'Simulated sent'){const value:CampaignDraft={id:`campaign-${Date.now()}`,subject:form.subject,body:form.body,segment:form.segment,tokens:['companyName','plan'],status,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()};status==='Draft'?emit('save',value):emit('send',value)}</script>
<template><div class="campaigns page-stack"><section class="page-intro"><div><span class="eyebrow">Outreach composer</span><h2>Campaign simulation</h2><p>Compose and preview retention outreach. No email provider is configured and no message leaves this browser.</p></div><span class="simulation">Simulation</span></section><section class="notice"><strong>Simulation only</strong><span>“Simulated sent” records a workflow event; it does not deliver email.</span></section><section class="grid"><form class="panel composer" @submit.prevent><label>Selected customer segment<select v-model="form.segment"><option>High risk</option><option>Under-utilised</option><option>All</option></select></label><label>Email subject<input v-model="form.subject"></label><label>Message body<textarea v-model="form.body" rows="10"></textarea></label><p>Personalisation tokens: <code v-pre>{{companyName}}</code> <code v-pre>{{plan}}</code></p><div><button @click="draft('Draft')">Save as draft</button><button class="primary-button" @click="draft('Simulated sent')">Mark as simulated sent</button></div></form><article class="panel preview"><span class="eyebrow">Preview · {{selected.length}} recipients</span><h3>{{previewSubject}}</h3><p>{{preview}}</p><small>Simulation — no provider configured</small></article></section><section class="panel history"><h3>Saved simulations</h3><p v-for="item in campaigns.slice().reverse()" :key="item.id"><strong>{{item.subject}}</strong><span>{{item.segment}} · {{item.status}}</span></p><div v-if="!campaigns.length" class="empty">No campaign drafts saved.</div></section></div></template>
<style scoped>.campaigns{max-width:1300px;margin:auto;padding:32px clamp(20px,3vw,48px) 56px}.page-intro{display:flex;align-items:end;justify-content:space-between}.simulation{padding:10px 16px;border-radius:999px;color:var(--color-brown);background:var(--color-peach);font-weight:800}.notice{display:flex;gap:14px;padding:18px;border-radius:16px;background:var(--color-mist)}.grid{display:grid;grid-template-columns:1fr 1fr;gap:18px}.composer,.preview,.history{padding:24px;border-radius:20px}.composer{display:grid;gap:14px}.composer label{font-size:12px;font-weight:700}.composer input,.composer select,.composer textarea{display:block;width:100%;margin-top:5px;padding:10px;border:1px solid var(--color-border);border-radius:10px}.composer div{display:flex;justify-content:flex-end;gap:10px}.composer button{padding:10px 14px;border:1px solid var(--color-border);border-radius:10px;background:#fff}.preview h3,.history h3{font:400 28px var(--font-display)}.preview p{white-space:pre-line;line-height:1.7}.preview small{color:var(--color-brown);font-weight:700}.history p{display:flex;justify-content:space-between;padding:12px 0;border-top:1px solid var(--color-border)}.history span{color:var(--color-muted)}.empty{padding:30px;text-align:center;color:var(--color-muted)}@media(max-width:750px){.grid{grid-template-columns:1fr}}</style>
